#include<bits/stdc++.h>
using namespace std;
long long d[201],c[201][201];
int main()
{
    long long n;
    scanf("%lld",&n);
    long long sum=0;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&d[i]);
        d[i]--;
        if(n==1)
        {
            if(d[i]==-1)
            {
                printf("1");
                return 0;
            }
            printf("0");
            return 0;
        }
        if(d[i]<0)
        {
            printf("0");
            return 0;
        }
        sum+=d[i];
    }
    if(sum!=n-2)
    {
        printf("0");
        return 0;
    }
    for(long long i=0;i<=150;i++)
    {
        c[i][0]=1;
        for(long long j=1;j<=i;j++)
        {
            c[i][j]=c[i-1][j]+c[i-1][j-1];
        }
    }
    long long ans=1;
    for(long long i=1;i<=n;i++)
    {
        ans=ans*c[sum][d[i]];
        sum-=d[i];
    }
    printf("%lld",ans);
    return 0;
}
